package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"strings"
	"sync"
	"time"

	"github.com/redis/go-redis/v9"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const (
	sessionKeyPrefix          = "session:"
	sessionExpiryKey          = "session:expiry"
	sessionLastActivityKey    = "session:last_activity"
	DefaultSandboxIdleTimeout = 15 * time.Minute
)

// RedisStore implements Store interface using Redis
type RedisStore struct {
	client redis.Client
}

// NewRedisStore creates a new Redis store
func NewRedisStore() (*RedisStore, error) {
	addr := os.Getenv("REDIS_ADDR")
	if addr == "" {
		return nil, errors.New("REDIS_ADDR environment variable is not set")
	}

	password := os.Getenv("REDIS_PASSWORD")
	passwordRequired := strings.ToLower(os.Getenv("REDIS_PASSWORD_REQUIRED")) != "false"

	if password == "" && passwordRequired {
		return nil, errors.New("REDIS_PASSWORD is required")
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	return &RedisStore{client: *client}, nil
}

func (r *RedisStore) Ping(ctx context.Context) error {
	return r.client.Ping(ctx).Err()
}

func (r *RedisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := sessionKeyPrefix + sessionID
	data, err := r.client.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
		return nil, err
	}
	return &sandbox, nil
}

func (r *RedisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return errors.New("expiresAt is required")
	}

	key := sessionKeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := r.client.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, sessionExpiryKey, redis.Z{Score: float64(sandbox.ExpiresAt.Unix()), Member: sandbox.SessionID})
	pipe.ZAdd(ctx, sessionLastActivityKey, redis.Z{Score: float64(time.Now().Unix()), Member: sandbox.SessionID})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *RedisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return errors.New("sandbox is nil")
	}

	key := sessionKeyPrefix + sandbox.SessionID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	// Use Set with XX flag (key must exist)
	result, err := r.client.SetXX(ctx, key, data, 0).Result()
	if err == redis.Nil || result == "" {
		return errors.New("key not exists")
	}
	return err
}

func (r *RedisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, sessionExpiryKey, sessionID)
	pipe.ZRem(ctx, sessionLastActivityKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *RedisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return r.listSandboxesByScore(ctx, sessionExpiryKey, 0, before.Unix(), limit)
}

func (r *RedisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	return r.listSandboxesByScore(ctx, sessionLastActivityKey, 0, before.Unix(), limit)
}

func (r *RedisStore) listSandboxesByScore(ctx context.Context, key string, min, max int64, limit int64) ([]*types.SandboxInfo, error) {
	ids, err := r.client.ZRangeByScore(ctx, key, &redis.ZRangeBy{
		Min:   fmt.Sprintf("%d", min),
		Max:   fmt.Sprintf("%d", max),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, ids)
}

func (r *RedisStore) loadSandboxesBySessionIDs(ctx context.Context, ids []string) ([]*types.SandboxInfo, error) {
	if len(ids) == 0 {
		return nil, nil
	}

	keys := make([]string, len(ids))
	for i, id := range ids {
		keys[i] = sessionKeyPrefix + id
	}

	results, err := r.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(results))
	for i, result := range results {
		if result == nil {
			continue
		}
		data, ok := result.(string)
		if !ok {
			continue
		}

		var sandbox types.SandboxInfo
		if err := json.Unmarshal([]byte(data), &sandbox); err != nil {
			klog.Warningf("Failed to unmarshal sandbox %s: %v", ids[i], err)
			continue
		}
		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

func (r *RedisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID is required")
	}

	if at.IsZero() {
		at = time.Now()
	}

	// Verify session exists
	key := sessionKeyPrefix + sessionID
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
