	}

	return sandboxes, nil
}

func (v *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID is required")
	}

	if at.IsZero() {
		at = time.Now()
	}

	// Verify session exists
	key := valkeySessionKeyPrefix + sessionID
	exists, err := v.client.Do(ctx, v.client.B().Exists().Key(key).Build()).AsBool()
	if err != nil {
		return err
	}
	if !exists {
		return ErrNotFound
	}

	return v.client.Do(ctx, v.client.B().Zadd().Key(valkeySessionLastActivityKey).ScoreMember().
		ScoreMember(float64(at.Unix()), sessionID).Build()).Error()
}

func (v *ValkeyStore) Close() error {
	v.client.Close()
	return nil
}

